import * as t from "io-ts";
import { AccountBaseBuildOptions } from "./accountBaseBuildOptions";
import { SubstrateFeeOptions } from "./substrateFeeOptions";
import { Optional } from "../../../utils";

export const SubstrateAccountBaseBuildOptions = t.intersection([
  AccountBaseBuildOptions,
  t.partial({
    fee: Optional(SubstrateFeeOptions),
  }),
]);

export type SubstrateAccountBaseBuildOptions = t.TypeOf<
  typeof SubstrateAccountBaseBuildOptions
>;
